&sdtLancamentoDasViagens.Clear() //Exclui os lançamentos anteriores Do Case // Case &Mode = 'ADC' //Quando for para adicionar as despesas // //Busca as DESPESAS Ativas // For Each Order EmpCod, FilCod, ViaCod, ViaLanCod // Where EmpCod = &parmEmpCod //Empresa // Where FilCod = &parmFilCod //Filial // Where ViaCod = &parmViaCod //Viagem // Where ViaLanSts = Status_AtivoInativo.ATIVO //Ativo // Where ViaLanTip <> 'A' AND ViaLanTip <> 'DE'//Todas as DESPESAS // // &sdtLancamentoDasViagensItem = New() // &sdtLancamentoDasViagensItem.EmpCod = EmpCod //Empresa // &sdtLancamentoDasViagensItem.FilCod = FilCod //Filial // &sdtLancamentoDasViagensItem.ViaCod = ViaCod //Viagem // &sdtLancamentoDasViagensItem.ViaLanCod = ViaLanCod //Código do Lançamento // &sdtLancamentoDasViagensItem.ViaLanDta = ViaLanDta //Data de Lançamento // &sdtLancamentoDasViagensItem.ViaLanFor = ViaLanFor //Fornecedor // &sdtLancamentoDasViagensItem.ViaLanPlanCod = ViaLanPlanCod //Plano de Contas // &sdtLancamentoDasViagensItem.ViaLanVeiKm = ViaLanVeiKm //KM do veículo na data da despesa // &sdtLancamentoDasViagensItem.VeiCod = VeiCod //Código do Veiculo // &sdtLancamentoDasViagensItem.ViaLanNumDoc = ViaLanNumDoc //Número do Documento Fiscal // &sdtLancamentoDasViagensItem.ViaLanObs = ViaLanObs //Observação/Descrição // &sdtLancamentoDasViagensItem.ViaLanVlr = ViaLanVlr //Valor // &sdtLancamentoDasViagens.Add(&sdtLancamentoDasViagensItem) // // EndFor // // //Conta quantas Despesas há // &Count = &sdtLancamentoDasViagens.Count // // //Adiciona as despesas a um XML para a visualização no grid // &ItensDoLancamento = &sdtLancamentoDasViagens.ToXml() // &WebSession.Set("!ItensLancamento", &ItensDoLancamento)
Case &Mode = 'INS' //Quando for para inserir duplicatas //Busca as DESPESAS Ativas For Each Order EmpCod, FilCod, ViaCod, ViaLanCod Where EmpCod = &parmEmpCod //Empresa Where FilCod = &parmFilCod //Filial Where ViaCod = &parmViaCod //Viagem Where ViaLanSts = Status_AtivoInativo.ATIVO //Ativo Where ViaLanTip <> 'A' AND ViaLanTip <> 'DE'//Todas as DESPESAS
&ViaLanNumDoc = ViaLanNumDoc //Número do Documento Fiscal &ViaLanDta = ViaLanDta //Data de Lançamento &ViaLanVlr = ViaLanVlr //Valor do Lançamento &ViaLanFor = ViaLanFor //Fornecedor &ViaLanPlanCod = ViaLanPlanCod //Plano de Contas &ViaLanVeiKm = ViaLanVeiKm //KM do veiculo na data da despesa &VeiCod = VeiCod //Código do Veiculo
//Busca o Veiculo Do 'BuscaVeiculo'
//Retorna o último código da Duplicata UltimoCodigoEmpresa.Call(domParCod.DUPLICATA, &parmEmpCod, &parmFilCod, &CreCod) &CreCod += 1
If ViaLanStsPag = Status_SimNao.Nao //Se o Lançamento não estiver sido pago ainda //Gera uma duplicata à Pagar aberta New EmpCod = &parmEmpCod //Empresa FilCod = &parmFilCod //Filial CreCod = &CreCod //Duplicata If Not ViaLanNumDoc.IsEmpty() CreDupNro = ViaLanNumDoc //Número do Documento Fiscal Else CreDupNro = Trim(Str(&CreCod)) + '-' + '1' EndIf CreDtaEms = ViaLanDta //Data do Lançamento CreDtaVct = &CreDtaVct //Data do Vencimento CreVlrDup = ViaLanVlr //Valor da Duplicata CreVlrSdo = ViaLanVlr //Saldo da Duplicata CreCliCod = ViaLanFor //Cliente da Duplicata CreRecPag = ReceberPagar.Pagar //Duplicata para pagar CreSts = Status_Duplicata.ATIVO //Duplicata Ativa CrePlanCod = ViaLanPlanCod //Plano de Contas CreOriDup = OrigemDuplicata.LancamentoManual //Lançamento Manual CreFilPgt = &parmFilCod //Filial de Pagamento CreVeikm = ViaLanVeiKm //KM do veiculo na data da despesa CreVeiPla = &CreVeiPla //Placa do Veiculo CreVeiCod = VeiCod //Código do Veiculo CreAbvDup = 'AVULSA' //Duplicata AVULSA CreFrpPgtoCod = 1 //Forma de pagamento CreViaCod = &parmViaCod //Código da Viagem CreCbrCod = 1 EndNew
Commit
Else //Se não, gera uma duplicata já paga e um recibo Do 'BuscaMovimento' EndIf
EndFor
//Gera uma Duplicata para pagamento do motorista Do 'GerarDuplicataMotorista'
EndCase
Sub 'GerarDuplicataMotorista'
For Each Order EmpCod, FilCod, ViaCod Where EmpCod = &parmEmpCod //Empresa Where FilCod = &parmFilCod //Filial Where ViaCod = &parmViaCod //Viagem
//Busca os totais lançados For Each Order EmpCod, FilCod, ViaCod, ViaLanCod
Do Case Case ViaLanTip = 'A' &TotAdiantamento += ViaLanVlr
Case ViaLanTip = 'DA' Or ViaLanTip = 'DM' or ViaLanTip = 'DV' And ViaLanStsPag = Status_SimNao.Sim &TotDespesas += ViaLanVlr
Case ViaLanTip = 'DE' &TotDevolucao += ViaLanVlr
EndCase
EndFor
//Saldo = Adiantamentos - Despesas Pagas &Saldo = &TotAdiantamento - &TotDespesas
//Vale = Saldo - Valor de Devoluções &Vale = &Saldo - &TotDevolucao
//Valor da Comissão com %
&ViaCteMotVlr = ViaCteMotVlr //Valor em Saldo = Valor de Comissão - Vale &AuxCreVlrDup = &ViaCteMotVlr - &Vale
//Retorna o plano de contas para o Vale RetornaConfSistema.Call(&parmEmpCod, &parmFilCod, domConfSistema.TCon014_PlanoAdiantamento, &TCon014_PlanoAdiantamento) RetornaCodigoPlanoContas.Call(&parmEmpCod, &TCon014_PlanoAdiantamento, &AuxPlanCod)
//Busca o último código da tabela de Duplicatas UltimoCodigoEmpresa.Call(domParCod.DUPLICATA, &parmEmpCod, &parmFilCod, &CreCod) &CreCod += 1
New EmpCod = &parmEmpCod //Empresa FilCod = &parmFilCod //Filial CreCod = &CreCod //Duplicata CreDupNro = Trim(Str(&CreCod)) + '-' + '1' //Número da Duplicata CreDtaEms = &Today //Data do Lançamento CreDtaVct = &CreDtaVct //Data do Vencimento CreVlrDup = ViaCteMotVlr //Valor da Duplicata CreVlrSdo = ViaCteMotVlr //Saldo da Duplicata CreCliCod = PesCod //Cliente da Duplicata CreRecPag = ReceberPagar.Pagar //Duplicata para pagar CreSts = Status_Duplicata.ATIVO //Duplicata Ativa CrePlanCod = &AuxPlanCod //Plano de Contas CreOriDup = OrigemDuplicata.LancamentoManual //Lançamento Manual CreFilPgt = &parmFilCod //Filial de Pagamento CreVeiPla = &CreVeiPla //Placa do Veiculo CreVeiCod = VeiCod //Código do Veiculo CreAbvDup = 'AVULSA' //Duplicata AVULSA CreFrpPgtoCod = 1 //Forma de pagamento CreViaCod = &parmViaCod //Código da Viagem CreCbrCod = 1 //Local de Cobrança EndNew
Commit
//Se houver vale If &Vale > 0 //Busca Conta bancária do motorista &CtaMotCod = PesCod Do 'BuscaBancoMotorista'
//busca o código do último movimento UltimoCodigoEmpresa.Call(domParCod.MOVIMENTO, &parmEmpCod, 0, &MovCod)
//movimento New EmpCod = &parmEmpCod // Empresa MovCod = &MovCod // Código MovDoc = Trim(Str(&CreCod)) + '-' + '1' // Número do Documento MovDtaPgt = &Today // Data do Lançamento MovDta = ServerDate() // Data do Movimento MovHor = ServerNow() // Hora do Lançamento MovCtaBanCod = &CtabanCod // Conta Bancária MovCreDeb = 'D' // Débito MovDtaCon = &Today // Data de Conferência MovTip = TipoMovimento.PagamentoDuplicata // Pagamento de Duplicata MovSts = Status_Caixa.Lancado // Lançado MovViaCod = &parmViaCod // Viagem When Duplicate &Error = 1 Return EndNew
//Item do Movimento New EmpCod = &parmEmpCod // Empresa MovCod = &MovCod // MOvimento MovItmCod = 1 // Movimento Item PlanCod = &AuxPlanCod // Plano de Contas MovItmVlr = &Vale // Valor MovItmCpl = 'DESCONTO SOBRE A COMISSÃO DA VIAGEM ' + Trim(Str(&parmViaCod)) + '! CONTA ORI: '+ Upper(trim(str(&CtabanCod))) MovCreFilCod = 0 MovCreCod = &CreCod // Duplicata MovCrePagCod = 1 // Duplicata de Pagamento MovTrnOriCod = &MovCod // Movimento de Origem MovTrnOriCodItm = 1 EndNew
//Pagamento da Duplicata New EmpCod = &parmEmpCod //Empresa FilCod = &parmFilCod //Filial CreCod = &CreCod //Duplicata CrePagCod = 1 //Código do Pagamento CrePagDta = &Today //Data de Pagamento CrePagVlr = &Vale //Valor do Pagamento CrePagTip = TipoDuplicataBaixa.Parcial //Valor Pago parcialmente CreMovCod = &MovCod //Movimento CreMovItmCod = 1 EndNew Commit
//Atualiza o saldo AtualizaSaldoDuplicata.call(&parmEmpCod, &CreCod, &parmFilCod) EndIf Exit EndFor
EndSub
Sub 'BuscaMovimento'
For Each Order EmpCod, MovCod Where EmpCod = &parmEmpCod //Empresa Where MovSts = Status_Caixa.Lancado //Status Lançado Where MovCreDeb = 'D' //Débito Where MovItmVlr = &ViaLanVlr //Valor do Movimento Where PlanCod = &ViaLanPlanCod When Not &ViaLanPlanCod.IsEmpty() //Plano de Contas Where MovItmSts = Status_Caixa.Lancado //Status do Item
//Duplicata Paga New EmpCod = &parmEmpCod //Empresa FilCod = &parmFilCod //Filial CreCod = &CreCod //Duplicata If Not &ViaLanNumDoc.IsEmpty() CreDupNro = &ViaLanNumDoc //Número do Documento Fiscal Else CreDupNro = Trim(Str(&CreCod)) + '-' + '1' EndIf CreDtaEms = &ViaLanDta //Data da Despesa CreDtaVct = &CreDtaVct //Data do Vencimento CreVlrDup = &ViaLanVlr //Valor da Despesa CreVlrSdo = 0 //Saldo = 0 porque já foi pago CreCliCod = &ViaLanFor //Cliente CreRecPag = ReceberPagar.Pagar //Pagar CreSts = Status_Duplicata.ATIVO //Status Ativo CrePlanCod = &ViaLanPlanCod //Plano de Contas CreOriDup = OrigemDuplicata.LancamentoManual //Lançamento Manual CreFilPgt = &parmFilCod //Filial de Pagamento CreVeikm = ViaLanVeiKm //KM do veiculo na data da despesa CreVeiPla = &CreVeiPla //Placa do Veiculo CreVeiCod = &VeiCod //Código do Veiculo CreAbvDup = 'AVULSA' //Avulsa CreFrpPgtoCod = 1 //Forma de Pagamento CreDtaPrmPag = MovDta //Data de Pagamento CreViaCod = &parmViaCod //Viagem CreCbrCod = 1 EndNew
MovCreCod = &CreCod //Acrescenta ao movimento o código da Duplicata MovCrePagCod = 1 //Item do Movimento
Commit
//Pagamento da Duplicata New EmpCod = &parmEmpCod //Empresa FilCod = &parmFilCod //Filial CreCod = &CreCod //Código da Duplicata CrePagCod = 1 //Código do Pagamento CrePagDta = MovDta //Data de Pagamento CrePagVlr = &ViaLanVlr //Valor do Pagamento CreMovCod = MovCod //Código do Movimento CreMovItmCod = MovItmCod //Item do Movimento CrePagTip = TipoDuplicataBaixa.Total //valor pago totalmente EndNew
Commit
//Busca o último código da Tabela recibo UltimoCodigoEmpresa.Call(domParCod.RECIBO, &parmEmpCod, &parmFilCod, &RcbCod)
//Busca o Nome do destinatário do Recibo Do 'BuscaPessoa'
//Recibo New EmpCod = &parmEmpCod //Empresa RcbCod = &RcbCod //Código do Recibo RcbDoc = &ViaLanNumDoc //Número do Documento Fiscal RcbTip = TipoRecibo.Pagar //Recibo para pagar RcbObs = MovItmCpl //Observação RcbVlr = &ViaLanVlr //Valor RcbDstCod = &ViaLanFor //Código do Destinatário RcbDstNom = &RcbDstNom //Nome do Destinatário RcbFilCod = &parmFilCod //Filial RcbDta = MovDta //Data do Recibo RcbHor = MovHor //Hora do Recibo RcbMovCod = MovCod //Código da Movimentação RcbMovItm = MovItmCod //Código do Item da Movimentação RcbCreCod = &CreCod //Duplicata RcbCrePagCod = 1 //Forma de Pagamento RcbCodeVR = 1000 * Random() //número aleatório EndNew
Commit EndFor
EndSub
Sub 'BuscaPessoa'
//Busca o Destinatário do Recibo For Each Order EmpCod, PesCod Where EmpCod = &parmEmpCod //Empresa Where PesCod = &ViaLanFor //Código do Destinatário
&RcbDstNom = PesRaz //Nome do Destinatário Exit EndFor
EndSub
Sub 'BuscaVeiculo'
//Busca o Veiculo For Each Order EmpCod, VeiCod Where EmpCod = &parmEmpCod //Empresa Where VeiCod = &VeiCod //Código do Veiculo
&CreVeiPla = VeiPla //Placa do Veiculo
Exit EndFor
EndSub
Sub 'BuscaBancoMotorista'
//Retorna conta bancária do motorista For Each Order EmpCod, CtabanCod Where EmpCod = &parmEmpCod //empresa Where CtaMotCod = &CtaMotCod //código do Motorista
&CtabanCod = CtabanCod //Conta bancária
Exit EndFor
EndSub
